local YXLog = CardEHT.YXLog
local YXTime = CardEHT.YXTime

local _cachePrint = print
-----------------------------------------------------------------

function LXFW.Info(s)
    return YXLog.Log(s)
end

function LXFW.Warn(s)
    return YXLog.LogWarning(s)
end

function LXFW.Error(s)
    if s == nil then return end
    s = tostring(s)
    if s == "" then return end
    return YXLog.LogError(s)
end

