---@class LxLog
LxLog = {}
local LxLog = LxLog
LXFW.LxLog = LxLog

LxLog.logEnabled = false
LxLog.logDepthMax = 6

local function _format_log(s, color)
    s = "["..YXTime.GetTimestampLogFormat().."]"..tostring(s)
    if not color then
        color = "999999ff"
    end
    local str = string.format("<color=#%s>", color)
    local partList = string.split(s, '\n')
    for k,v in ipairs(partList) do
        if (k < 2) then
            str = string.format("%s%s\n", str, v)
        elseif (k == 2) then
            str = string.format("%s%s</color>\n<color=#%s>", str, v, color)
        else
            str = string.format("%s%s\n", str, v)
        end
    end
    str = str .. "</color>"
    return str
end

function LxLog.log(msg, color)
    if not LxLog.logEnabled then return end
    LXFW.Info(_format_log(msg, color))
end


---table格式化成字符串
function LxLog.format_table_to_string(tbl, depthMax, curDepth, curStr)
    depthMax = depthMax or LxLog.logDepthMax
    curDepth = curDepth or 1
    curStr = curStr or ""
    local strSplit = "    "

    local strHead = ""
    if (curDepth > 1) then
        strHead = string.rep(strSplit,curDepth)
    end

    if (curDepth > depthMax) then
        return "\n" .. strHead .. "depthMax reached " .. depthMax
    end

    local objType = type(tbl)

    local dataTbl = {}
    if (objType == 'table') then
        table.insert(dataTbl,strHead)
        table.insert(dataTbl,tostring(tbl))
        table.insert(dataTbl," | ")
        if (tbl.GetClassName) then
            table.insert(dataTbl,tbl:GetClassName())
            table.insert(dataTbl," | ")
        end
        table.insert(dataTbl,"\n")
        strHead = strHead .. strSplit
        for k, v in pairs(tbl) do
            table.insert(dataTbl, strHead)
            table.insert(dataTbl, tostring(k))
            table.insert(dataTbl,"=>")
            table.insert(dataTbl, LxLog.format_table_to_string(v, depthMax, curDepth+1, nil))
        end
    elseif (objType == 'userdata') then
        if (not LXFW.LxUnity.IsValidObject(tbl)) then
            tbl = "null"
        end
        table.insert(dataTbl,strHead)
        table.insert(dataTbl,tostring(tbl))
        table.insert(dataTbl,"\n")

        if (string.find(tostring(tbl), "System.Collections.Generic.List") == 1) then
            strHead = strHead .. strSplit
            for i = 1, tbl.Count do
                table.insert(dataTbl, strHead)
                table.insert(dataTbl, tostring(i-1))
                table.insert(dataTbl,"=>")
                table.insert(dataTbl,tostring(tbl[i-1]))
                table.insert(dataTbl,"\n")
            end
        end
    else
        table.insert(dataTbl,strHead)
        table.insert(dataTbl,tostring(tbl))
        table.insert(dataTbl,"\n")
    end
    curStr = table.concat(dataTbl)
    return curStr
end

