LxLog.TAG_SEND = "[send]"
LxLog.TAG_RECV = "[recv]"
LxLog.TAG_MEMORY = "[memory]"
LxLog.TAG_LOGIN = "[login]"
LxLog.TAG_GAME = "[game]"
LxLog.TAG_TCPCLOSE = "[tcp_close]"
LxLog.TAG_WEB = "[web]"
LxLog.TAG_NINFO = "[N]"
LxLog.TAG_RINFO = "[R]"
LxLog.TAG_EINFO = "[E]"

LxLog.TAG_COLOR = {
    [LxLog.TAG_SEND] 		= "8bee4bff",
    [LxLog.TAG_RECV]  		= "6d80ddff",
    [LxLog.TAG_MEMORY]  	= "c244f0ff",
    [LxLog.TAG_LOGIN]  		= "f0c801ff",
    [LxLog.TAG_GAME]  		= "349aeaff",
    [LxLog.TAG_TCPCLOSE]  	= "ff0001ff",
    [LxLog.TAG_WEB]  		= "EE7875ff",
    [LxLog.TAG_NINFO]  		= "999999ff",
    [LxLog.TAG_RINFO]  		= "dc143cff",
    [LxLog.TAG_EINFO]  		= "e5381eff",
}

function LxLog.info(s, tag)
    if not LxLog.logEnabled then return end
    local color
    if tag then
        color = LxLog.TAG_COLOR[tag]
        s = tostring(tag)..""..s
    end
    if not color then color = LxLog.TAG_COLOR[LxLog.TAG_NINFO] end
    LxLog.log(s,color)
end

function LxLog.SEND(s) LxLog.info(s, LxLog.TAG_SEND) end
function LxLog.RECV(s) LxLog.info(s, LxLog.TAG_RECV) end
function LxLog.MEMORY(s) LxLog.info(s, LxLog.TAG_MEMORY) end
function LxLog.LOGIN(s) LxLog.info(s, LxLog.TAG_LOGIN) end
function LxLog.GAME(s) LxLog.info(s, LxLog.TAG_GAME) end
function LxLog.TCP_CLOSE(s) LxLog.info(s, LxLog.TAG_TCPCLOSE) end
function LxLog.WEB(s) LxLog.info(s, LxLog.TAG_WEB) end
