        "[",
        tostring(tag),
        "] ",
        string.format(fmt, ...)
    }
    --print(table.concat(t))
    --if LOG_TRACE then
    _YXLog(table.concat(t) .. debug.traceback("", 3))
    --else
    --    _Log(table.concat(t))
    --end
end

function printError(tag, fmt, ...)
    if LxLog.logEnabled then
        _printLog(tag or "ERR", "<color=red>" .. tostring(fmt) .. "</color>", ...)
    end
end

function printInfo(tag, fmt, ...)
    if LxLog.logEnabled then
        _printLog(tag or "INFO", tostring(fmt), ...)
    end
end

function gprint(...)
    if not LxLog.logEnabled then return end
    _cachePrint(...)
end

function print(msg)
    if not LxLog.logEnabled then return end
    _cachePrint(debug.traceback(msg,2))
end

function printInfoN(...)
    if not LxLog.logEnabled then return end

    local objList = {...}

    local str = ""
    for _,v in ipairs(objList) do
        str = str .. LxLog.format_table_to_string(v)
    end

    LxLog.info(str, LxLog.TAG_NINFO)
end

function printInfoNR(...)
    if not LxLog.logEnabled then return end

    local objList = {...}
    local str = ""
    for _,v in ipairs(objList) do
        str = str .. LxLog.format_table_to_string(v)
    end
    LxLog.info(str, LxLog.TAG_RINFO)
end

function printErrorN(...)
    if not LxLog.logEnabled then return end

    local objList = {...}
    local str = ""
    for _,v in ipairs(objList) do
        if v then
            str = str.." "..tostring(v)
        end
    end
    LxLog.info(str, LxLog.TAG_EINFO)
end

